import React from 'react';
import { Link } from 'react-router-dom';

const NotFoundPage = () => {
  return (
    <div className="min-h-screen bg-white flex flex-col justify-center py-12 sm:px-6 lg:px-8">
      <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
        <div className="text-center">
          <h1 className="text-9xl font-extrabold text-[#003087]">404</h1>
          <h2 className="mt-4 text-3xl font-bold text-gray-900">页面未找到</h2>
          <p className="mt-2 text-base text-gray-500">
            很抱歉，您访问的页面不存在。
          </p>
          <div className="mt-6">
            <Link
              to="/"
              className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-[#003087] hover:bg-blue-900"
            >
              返回首页
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
};

export default NotFoundPage;
